// Generate test payloads for all dental webhooks
const baseUrl = $vars.N8N_HOST || 'zappai.app.n8n.cloud';
const testTimestamp = new Date().toISOString();
const futureDate = new Date();
futureDate.setDate(futureDate.getDate() + 3);
futureDate.setHours(10, 0, 0, 0);

const tests = [
  {
    name: 'Lead - Webform',
    endpoint: `https://${baseUrl}/webhook/dental/lead/webform`,
    method: 'POST',
    payload: {
      name: 'Test User Webform',
      phone: '+40712345678',
      email: 'test.webform@example.com',
      language: 'ro',
      procedure: 'cleaning',
      notes: 'Test from harness - webform'
    }
  },
  {
    name: 'Lead - Missed Call',
    endpoint: `https://${baseUrl}/webhook/dental/lead/missed-call`,
    method: 'POST',
    payload: {
      phone: '+40712345679',
      caller_id: '+40712345679',
      timestamp: testTimestamp
    }
  },
  {
    name: 'Lead - Meta',
    endpoint: `https://${baseUrl}/webhook/dental/lead/meta`,
    method: 'POST',
    payload: {
      name: 'Test User Meta',
      phone: '+40712345680',
      email: 'test.meta@example.com',
      language: 'en',
      interest: 'whitening',
      message: 'Test from harness - meta lead'
    }
  },
  {
    name: 'Appointment Confirmed',
    endpoint: `https://${baseUrl}/webhook/dental/appointment/confirmed`,
    method: 'POST',
    payload: {
      lead_id: 'test_lead_001',
      name: 'Test Patient',
      email: 'test.patient@example.com',
      phone: '+40712345681',
      appointment_time: futureDate.toISOString(),
      procedure: 'consultation',
      language: 'ro'
    }
  },
  {
    name: 'Appointment Completed',
    endpoint: `https://${baseUrl}/webhook/dental/appointment/completed`,
    method: 'POST',
    payload: {
      appointment_id: 'apt_test_001',
      name: 'Test Completed Patient',
      email: 'test.completed@example.com',
      language: 'ro'
    }
  }
];

return tests.map(test => ({ json: test }));

// Collect test result
const testData = $('Split Into Batches').first().json;
const response = $input.first().json;
const statusCode = $input.first().json.statusCode || 200;

const success = statusCode >= 200 && statusCode < 300;

return {
  json: {
    test_name: testData.name,
    endpoint: testData.endpoint,
    status: success ? 'PASSED' : 'FAILED',
    status_code: statusCode,
    response_preview: JSON.stringify(response).substring(0, 200)
  }
};

// Summarize all test results
const results = $input.all().map(i => i.json);
const passed = results.filter(r => r.status === 'PASSED').length;
const failed = results.filter(r => r.status === 'FAILED').length;

return [{
  json: {
    summary: {
      total_tests: results.length,
      passed: passed,
      failed: failed,
      success_rate: `${Math.round(passed / results.length * 100)}%`
    },
    tests: results,
    timestamp: new Date().toISOString()
  }
}];
